import { type IQueryHandler, QueryHandler } from "@nestjs/cqrs";
import { InjectRepository } from "@nestjs/typeorm";
import { Repository } from "typeorm";

import { PaymentEntity } from "../../payment.entity.ts";
import { GetUserPaymentsQuery } from "./get-user-payments.query.ts";

@QueryHandler(GetUserPaymentsQuery)
export class GetUserPaymentsHandler
  implements IQueryHandler<GetUserPaymentsQuery, PaymentEntity[]>
{
  constructor(
    @InjectRepository(PaymentEntity)
    private readonly paymentRepository: Repository<PaymentEntity>,
  ) {}

  async execute(query: GetUserPaymentsQuery): Promise<PaymentEntity[]> {
    return this.paymentRepository.find({
      where: { userId: query.userId },
      order: { createdAt: "DESC" },
    });
  }
}
